const input = $input.first().json.data
const regex = /[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.(?!jpeg|jpg|png|gif|webp|svg)[a-zA-Z]{2,}/g
const emails = input.match(regex)
return {json: {emails:emails}}

// n8n Code node: safer Google Maps-like extractor (strip JS, limit noise)
// Input: $input.all() items with HTML/text in item.json.data (or item.json.raw)
// Output: array of { json: { website, name, address, phone } }
// Adjust maxResults if needed (200-300 recommended)

const maxResults = 200; // change to up to ~300 if you need more
const inputs = $input.all();

function safeStr(x){ return (x||'').toString(); }
function normalizeWebsite(w){
  if(!w) return '';
  w = w.replace(/[.,;:)\]]+$/,'').trim();
  w = w.replace(/^https?:\/\//i,'').replace(/^www\./i,'');
  if(!/\.[a-z]{2,6}(\/|$)/i.test(w)) return '';
  return 'http://' + w.replace(/\/+$/,'') + '/';
}
function normalizePhone(raw){
  if(!raw) return '';
  let s = raw.replace(/[^\d+]/g,'');
  const hasPlus = s.startsWith('+');
  s = s.replace(/^\+/, '');
  if(s.length < 7) return '';
  if(s.length === 10) return '+1' + s;
  if(s.length === 11 && s.startsWith('1')) return '+' + s;
  if(s.length >= 8 && s.length <= 15) return (hasPlus?'+':'+') + s;
  return '';
}

// Conservative regexes
const websiteRegex = /\b((?:https?:\/\/)?(?!maps\.google|google\.com|gstatic\.|accounts\.google|youtube\.com|facebook\.com|twitter\.com|instagram\.com)[a-z0-9\-._~%]+\.[a-z]{2,6}(?:\/[^\s"'>]*)?)/ig;
const phoneRegex = /(\+?\d{1,3}[\s.\-]?)?(?:\(?\d{3}\)?[\s.\-]?\d{3}[\s.\-]?\d{4}|\d{3}[\s.\-]\d{4}|\d{2,4}[\s.\-]\d{2,4}[\s.\-]\d{2,4})/g;
const postalRegex = /[A-Za-z]\d[A-Za-z][ -]?\d[A-Za-z]\d/; // Canada
const streetRegex = /\d{1,5}\s+[A-Za-z0-9.'\-\s]{3,60}\b(?:Street|St|Avenue|Ave|Road|Rd|Boulevard|Blvd|Drive|Dr|Lane|Ln|Court|Ct|Way|Terrace|Place|Square|Trail|Highway|Hwy|Circle|Cir)\b/i;
const provinceRegex = /\b(MB|ON|AB|BC|SK|QC|NB|NL|NS|PE|NT|YT)\b/i;

// Helpers to remove scripts and JS noise
function stripScriptsAndJS(html){
  // remove <script>...</script> and <style>...</style>
  let s = safeStr(html).replace(/<script[\s\S]*?<\/script>/gi, ' ')
                        .replace(/<style[\s\S]*?<\/style>/gi, ' ');
  // remove long JS-like lines that contain obvious tokens
  s = s.split(/\n/).filter(line => {
    const t = line.trim();
    if(!t) return false;
    if(/function\(|window\.|APP_OPTIONS|kEI=|var g|google\.maps|initMap\(|_init|__gm|_PAGE_DATA/i.test(t)) return false;
    // drop inline JSON blobs that are huge
    if(t.length > 800) return false;
    return true;
  }).join('\n');
  return s;
}

function htmlToLines(html){
  return stripScriptsAndJS(html)
    .replace(/<br\s*\/?>/gi,'\n')
    .replace(/<\/(div|p|li|span|h[1-6])>/gi,'\n')
    .replace(/<[^>]+>/g,' ')
    .split(/\n+/).map(l => l.trim()).filter(Boolean);
}

// Extractors per block
function extractFromBlock(block){
  const raw = safeStr(block);
  const lines = htmlToLines(raw);

  // Website: first suitable, filtered
  let website = '';
  const wMatches = [...new Set((raw.match(websiteRegex) || []).map(m=>m.trim()))];
  for(const m of wMatches){
    if(!/maps\.google|gstatic|googleusercontent|accounts\.google/i.test(m) && /\.[a-z]{2,6}/i.test(m)){
      website = normalizeWebsite(m.replace(/^https?:\/\//i,'').replace(/^www\./i,''));
      if(website) break;
    }
  }

  // Phone: first reasonable occurrence
  let phone = '';
  const ph = (raw.match(phoneRegex) || []).map(x => x.trim());
  for(const p of ph){
    const d = p.replace(/\D/g,'');
    if(d.length >= 7 && d.length <= 15){ phone = normalizePhone(p); break; }
  }

  // Address: look for postal codes first, else street pattern, else province+comma chunk
  let address = '';
  for(const ln of lines){
    if(postalRegex.test(ln) && /\d/.test(ln)){ address = ln; break; }
  }
  if(!address){
    for(const ln of lines){
      if(streetRegex.test(ln)){ address = ln; break; }
    }
  }
  if(!address){
    // look for line containing province abbreviations + comma (e.g., "Steinbach, MB")
    for(const ln of lines){
      if(provinceRegex.test(ln) && /,/.test(ln)) { address = ln; break; }
    }
  }
  if(address){
    // clean trailing UI words
    address = address.replace(/\b(Open|Closes|Hours|Closed|Directions|Save|Nearby|Send to phone|Share|Claim this business)\b.*$/i,'').trim();
    // ensure not too long
    if(address.length > 200) address = address.slice(0,200).trim();
  }

  // Name: try role heading / h1-h2 / meta og:title, or line before address, or first short line
  let name = '';
  const heading = raw.match(/role=["']heading["'][^>]*>([^<]{2,150})</i) || raw.match(/<h[1-3][^>]*>([^<]{2,150})<\/h[1-3]>/i);
  if(heading) name = heading[1].trim();
  if(!name){
    const meta = raw.match(/<meta[^>]*(?:property=["']og:title["']|name=["']title["'])[^>]*content=["']([^"']+)["']/i);
    if(meta) name = meta[1].trim();
  }
  if(!name && address){
    const idx = lines.findIndex(l => l.includes(address));
    if(idx > 0){
      const cand = lines[idx - 1];
      if(cand && cand.length < 120 && !/Open|Closes|Hours|Save|Nearby/i.test(cand)) name = cand.trim();
    }
  }
  if(!name && lines.length){
    // pick first short, clean line (avoid ones that look like UI)
    for(const ln of lines){
      if(ln.length > 2 && ln.length < 120 && !/Open|Closes|Hours|Save|Nearby|Photos|Reviews|Directions/i.test(ln)){
        name = ln.trim(); break;
      }
    }
  }
  if(name.length > 150) name = name.slice(0,150).trim();

  // Only consider this block useful if it has at least one of: website, (name+address), or phone
  const useful = website || (name && address) || phone;
  if(!useful) return null;

  return { website, name, address, phone };
}

// MAIN: collect blocks from all inputs, extract, dedupe, cap
const blocks = [];
for(const item of inputs){
  const rawCandidate = safeStr(item.json?.data || item.json?.raw || item.json?.html || item.json?.page || JSON.stringify(item.json || {}));
  if(!rawCandidate) continue;

  // If the rawCandidate seems to be a single listing (short), push as-is
  if(rawCandidate.length < 5000 && (/<h1|role=["']heading|class=["']section-hero-header|aria-label=["']Result/i.test(rawCandidate))){
    blocks.push(rawCandidate);
    continue;
  }

  // else split conservatively by likely separators used in Maps results
  const parts = rawCandidate.split(/data-result-index=|class=["'][^"']*(?:section-result|place-card|place-result|search-result|section-result|result-card)[^"']*["']|role=["']article|aria-label=["']Result/i);
  for(const p of parts){
    if(safeStr(p).length > 60) blocks.push(p);
    if(blocks.length >= maxResults*2) break; // collect a bit more to allow dedupe
  }
  if(blocks.length >= maxResults*2) break;
}

// extract and dedupe
const outputs = [];
const seen = new Set();
for(const b of blocks){
  if(outputs.length >= maxResults) break;
  const ex = extractFromBlock(b);
  if(!ex) continue;
  // make dedupe tokens
  const toks = [];
  if(ex.website) toks.push('w:' + ex.website);
  if(ex.phone) toks.push('p:' + ex.phone);
  if(ex.name && ex.address) toks.push('n:' + (ex.name + '|' + ex.address).slice(0,200));
  let skip = false;
  for(const t of toks){
    if(seen.has(t)){ skip = true; break; }
  }
  if(skip) continue;
  for(const t of toks) seen.add(t);
  outputs.push({ json: { website: ex.website, name: ex.name, address: ex.address, phone: ex.phone } });
}

// Guarantee an array return
return outputs;

